const getColor = (pnl: number) => {
  if (pnl > 3) return 'bg-green-600';
  if (pnl > 1) return 'bg-green-400';
  if (pnl > 0) return 'bg-green-200';
  if (pnl < -3) return 'bg-red-600';
  if (pnl < -1) return 'bg-red-400';
  if (pnl < 0) return 'bg-red-200';
  return 'bg-gray-100';
};

