'use client';
import { useState, useRef, useEffect } from 'react';
import { Search, Clock, TrendingUp } from 'lucide-react';
import { useRouter } from 'next/navigation';

export function GlobalSearch() {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState([]);
  const [recent, setRecent] = useState<string[]>([]);
  const [open, setOpen] = useState(false);
  const router = useRouter();
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem('fionera_recent_searches');
    if (saved) setRecent(JSON.parse(saved));
  }, []);

  useEffect(() => {
    if (!query || query.length < 2) { setResults([]); return; }
    const timer = setTimeout(() => {
      fetch(`/api/search?q=${encodeURIComponent(query)}&limit=8`)
        .then(r => r.json())
        .then(data => setResults(data.results));
    }, 200);
    return () => clearTimeout(timer);
  }, [query]);

  const handleSelect = (symbol: string) => {
    const updated = [symbol, ...recent.filter(r => r !== symbol)].slice(0, 5);
    setRecent(updated);
    localStorage.setItem('fionera_recent_searches', JSON.stringify(updated));
    router.push(`/markets/${symbol.toLowerCase()}`);
    setOpen(false);
    setQuery('');
  };

  return (
    <div className="global-search relative">
      <div className="search-input flex items-center gap-2 px-3 py-2 border rounded-xl bg-gray-50 focus-within:ring-2 ring-blue-500">
        <Search size={16} className="text-gray-400" />
        <input ref={inputRef} placeholder="Search symbols, companies..." value={query} onChange={e => setQuery(e.target.value)} onFocus={() => setOpen(true)} className="flex-1 bg-transparent outline-none text-sm" />
        {query && <button onClick={() => setQuery('')} className="text-gray-400 hover:text-gray-600">×</button>}
      </div>
      {open && (
        <div className="search-dropdown absolute top-full left-0 right-0 mt-1 bg-white border rounded-xl shadow-xl z-50 overflow-hidden">
          {results.length > 0 ? (
            <ul>{results.map((r: any) => (<li key={r.symbol} onClick={() => handleSelect(r.symbol)} className="flex items-center gap-3 px-4 py-3 hover:bg-gray-50 cursor-pointer"><TrendingUp size={14} className="text-gray-400" /><div><p className="font-medium text-sm">{r.symbol}</p><p className="text-xs text-gray-500">{r.name}</p></div><span className="ml-auto text-sm font-mono">{r.price}</span></li>))}</ul>
          ) : recent.length > 0 && !query ? (
            <div className="px-4 py-2"><p className="text-xs text-gray-400 mb-2 flex items-center gap-1"><Clock size={12}/>Recent</p>{recent.map(r => (<button key={r} onClick={() => handleSelect(r)} className="block w-full text-left px-2 py-1.5 text-sm hover:bg-gray-50 rounded">{r}</button>))}</div>
          ) : query.length >= 2 ? (
            <p className="px-4 py-6 text-center text-sm text-gray-400">No results for "{query}"</p>
          ) : null}
        </div>
      )}
    </div>
  );
}

